    CONSTRUCTOR_ID = 661470918
    __slots__ = ('msg_id', 'answer_msg_id', 'bytes', 'status')
    def __init__(self, msg_id: int, answer_msg_id: int, bytes: int, status: int):
        self.msg_id = msg_id
        self.answer_msg_id = answer_msg_id
        self.bytes = bytes
        self.status = status
    def to_dict(self):
        return {"msg_id": self.msg_id, "answer_msg_id": self.answer_msg_id, "bytes": self.bytes, "status": self.status}
    def _bytes(self):
        writer = BinaryWriter()
        writer.write_int(661470918, signed=False)
        writer.write_long(self.msg_id, signed=False)
        writer.write_long(self.answer_msg_id, signed=False)
        writer.write_int(self.bytes, signed=True)
        writer.write_int(self.status, signed=True)
        return writer.get_bytes()
    @classmethod
    def from_reader(cls, reader):
        msg_id = reader.read_long()
        answer_msg_id = reader.read_long()
        bytes = reader.read_int()
        status = reader.read_int()
        return cls(msg_id, answer_msg_id, bytes, status)

