@register
class Document(TLObject):
    CONSTRUCTOR_ID = 2413085912
    __slots__ = ('id', 'access_hash', 'file_reference', 'date', 'mime_type', 'size', 'thumbs', 'video_thumbs', 'dc_id', 'attributes')
    def __init__(self, id: int, access_hash: int, file_reference: bytes, date: int, mime_type: str, size: int, dc_id: int, attributes: 'Vector', thumbs: 'Vector' = None, video_thumbs: 'Vector' = None):
        self.id = id
        self.access_hash = access_hash
        self.file_reference = file_reference
        self.date = date
        self.mime_type = mime_type
        self.size = size
        self.thumbs = thumbs
        self.video_thumbs = video_thumbs
        self.dc_id = dc_id
        self.attributes = attributes
    def to_dict(self):
        return {"id": self.id, "access_hash": self.access_hash, "file_reference": self.file_reference, "date": self.date, "mime_type": self.mime_type, "size": self.size, "thumbs": self.thumbs, "video_thumbs": self.video_thumbs, "dc_id": self.dc_id, "attributes": self.attributes}
    def _bytes(self):
        writer = BinaryWriter()
        writer.write_int(2413085912, signed=False)
        flags = 0
        if self.thumbs is not None: flags |= 1 << 0
        if self.video_thumbs is not None: flags |= 1 << 1
        writer.write_int(flags, signed=False)
        writer.write_long(self.id, signed=False)
        writer.write_long(self.access_hash, signed=False)
        writer.write_bytes(self.file_reference)
        writer.write_int(self.date, signed=True)
        writer.write_string(self.mime_type)
        writer.write_long(self.size, signed=False)
        if flags & (1 << 0):
            writer.write(bytes(self.thumbs))
        if flags & (1 << 1):
            writer.write(bytes(self.video_thumbs))
        writer.write_int(self.dc_id, signed=True)
        writer.write(bytes(self.attributes))
        return writer.get_bytes()
    @classmethod
    def from_reader(cls, reader):
        flags = reader.read_int(signed=False)
        id = reader.read_long()
        access_hash = reader.read_long()
        file_reference = reader.read_bytes()
        date = reader.read_int()
        mime_type = reader.read_string()
        size = reader.read_long()
        if flags & (1 << 0):
            thumbs = reader.tgread_object()
        else:
            thumbs = None
        if flags & (1 << 1):
            video_thumbs = reader.tgread_object()
        else:
            video_thumbs = None
        dc_id = reader.read_int()
        attributes = reader.tgread_object()
        return cls(id, access_hash, file_reference, date, mime_type, size, thumbs, video_thumbs, dc_id, attributes)

