@register
class Game(TLObject):
    CONSTRUCTOR_ID = 3187238203
    __slots__ = ('id', 'access_hash', 'short_name', 'title', 'description', 'photo', 'document')
    def __init__(self, id: int, access_hash: int, short_name: str, title: str, description: str, photo: 'Photo', document: 'Document' = None):
        self.id = id
        self.access_hash = access_hash
        self.short_name = short_name
        self.title = title
        self.description = description
        self.photo = photo
        self.document = document
    def to_dict(self):
        return {"id": self.id, "access_hash": self.access_hash, "short_name": self.short_name, "title": self.title, "description": self.description, "photo": self.photo, "document": self.document}
    def _bytes(self):
        writer = BinaryWriter()
        writer.write_int(3187238203, signed=False)
        flags = 0
        if self.document is not None: flags |= 1 << 0
        writer.write_int(flags, signed=False)
        writer.write_long(self.id, signed=False)
        writer.write_long(self.access_hash, signed=False)
        writer.write_string(self.short_name)
        writer.write_string(self.title)
        writer.write_string(self.description)
        writer.write(bytes(self.photo))
        if flags & (1 << 0):
            writer.write(bytes(self.document))
        return writer.get_bytes()
    @classmethod
    def from_reader(cls, reader):
        flags = reader.read_int(signed=False)
        id = reader.read_long()
        access_hash = reader.read_long()
        short_name = reader.read_string()
        title = reader.read_string()
        description = reader.read_string()
        photo = reader.tgread_object()
        if flags & (1 << 0):
            document = reader.tgread_object()
        else:
            document = None
        return cls(id, access_hash, short_name, title, description, photo, document)

