@register
class PageTableCell(TLObject):
    CONSTRUCTOR_ID = 878078826
    __slots__ = ('header', 'align_center', 'align_right', 'valign_middle', 'valign_bottom', 'text', 'colspan', 'rowspan')
    def __init__(self, header: bool = None, align_center: bool = None, align_right: bool = None, valign_middle: bool = None, valign_bottom: bool = None, text: 'RichText' = None, colspan: int = None, rowspan: int = None):
        self.header = header
        self.align_center = align_center
        self.align_right = align_right
        self.valign_middle = valign_middle
        self.valign_bottom = valign_bottom
        self.text = text
        self.colspan = colspan
        self.rowspan = rowspan
    def to_dict(self):
        return {"header": self.header, "align_center": self.align_center, "align_right": self.align_right, "valign_middle": self.valign_middle, "valign_bottom": self.valign_bottom, "text": self.text, "colspan": self.colspan, "rowspan": self.rowspan}
    def _bytes(self):
        writer = BinaryWriter()
        writer.write_int(878078826, signed=False)
        flags = 0
        if self.header: flags |= 1 << 0
        if self.align_center: flags |= 1 << 3
        if self.align_right: flags |= 1 << 4
        if self.valign_middle: flags |= 1 << 5
        if self.valign_bottom: flags |= 1 << 6
        if self.text is not None: flags |= 1 << 7
        if self.colspan is not None: flags |= 1 << 1
        if self.rowspan is not None: flags |= 1 << 2
        writer.write_int(flags, signed=False)
        if flags & (1 << 7):
            writer.write(bytes(self.text))
        if flags & (1 << 1):
            writer.write_int(self.colspan, signed=True)
        if flags & (1 << 2):
            writer.write_int(self.rowspan, signed=True)
        return writer.get_bytes()
    @classmethod
    def from_reader(cls, reader):
        flags = reader.read_int(signed=False)
        header = bool(flags & (1 << 0))
        align_center = bool(flags & (1 << 3))
        align_right = bool(flags & (1 << 4))
        valign_middle = bool(flags & (1 << 5))
        valign_bottom = bool(flags & (1 << 6))
        if flags & (1 << 7):
            text = reader.tgread_object()
        else:
            text = None
        if flags & (1 << 1):
            colspan = reader.read_int()
        else:
            colspan = None
        if flags & (1 << 2):
            rowspan = reader.read_int()
        else:
            rowspan = None
        return cls(header, align_center, align_right, valign_middle, valign_bottom, text, colspan, rowspan)

