class KeyboardButtonStyle(TLObject):
    CONSTRUCTOR_ID = 1339896880
    __slots__ = ('bg_primary', 'bg_danger', 'bg_success', 'icon')
    def __init__(self, bg_primary: bool = None, bg_danger: bool = None, bg_success: bool = None, icon: int = None):
        self.bg_primary = bg_primary
        self.bg_danger = bg_danger
        self.bg_success = bg_success
        self.icon = icon
    def to_dict(self):
        return {"bg_primary": self.bg_primary, "bg_danger": self.bg_danger, "bg_success": self.bg_success, "icon": self.icon}
    def _bytes(self):
        writer = BinaryWriter()
        writer.write_int(1339896880, signed=False)
        flags = 0
        if self.bg_primary: flags |= 1 << 0
        if self.bg_danger: flags |= 1 << 1
        if self.bg_success: flags |= 1 << 2
        if self.icon is not None: flags |= 1 << 3
        writer.write_int(flags, signed=False)
        if flags & (1 << 3):
            writer.write_long(self.icon, signed=False)
        return writer.get_bytes()
    @classmethod
    def from_reader(cls, reader):
        flags = reader.read_int(signed=False)
        bg_primary = bool(flags & (1 << 0))
        bg_danger = bool(flags & (1 << 1))
        bg_success = bool(flags & (1 << 2))
        if flags & (1 << 3):
            icon = reader.read_long()
        else:
            icon = None
        return cls(bg_primary, bg_danger, bg_success, icon)

