@register
class AiComposeTone(TLObject):
    CONSTRUCTOR_ID = 3489021609
    __slots__ = ('creator', 'id', 'access_hash', 'slug', 'title', 'emoji_id', 'prompt', 'installs_count', 'author_id', 'example_english')
    def __init__(self, id: int, access_hash: int, slug: str, title: str, creator: bool = None, emoji_id: int = None, prompt: str = None, installs_count: int = None, author_id: int = None, example_english: 'AiComposeToneExample' = None):
        self.creator = creator
        self.id = id
        self.access_hash = access_hash
        self.slug = slug
        self.title = title
        self.emoji_id = emoji_id
        self.prompt = prompt
        self.installs_count = installs_count
        self.author_id = author_id
        self.example_english = example_english
    def to_dict(self):
        return {"creator": self.creator, "id": self.id, "access_hash": self.access_hash, "slug": self.slug, "title": self.title, "emoji_id": self.emoji_id, "prompt": self.prompt, "installs_count": self.installs_count, "author_id": self.author_id, "example_english": self.example_english}
    def _bytes(self):
        writer = BinaryWriter()
        writer.write_int(3489021609, signed=False)
        flags = 0
        if self.creator: flags |= 1 << 0
        if self.emoji_id is not None: flags |= 1 << 1
        if self.prompt is not None: flags |= 1 << 4
        if self.installs_count is not None: flags |= 1 << 2
        if self.author_id is not None: flags |= 1 << 3
        if self.example_english is not None: flags |= 1 << 5
        writer.write_int(flags, signed=False)
        writer.write_long(self.id, signed=False)
        writer.write_long(self.access_hash, signed=False)
        writer.write_string(self.slug)
        writer.write_string(self.title)
        if flags & (1 << 1):
            writer.write_long(self.emoji_id, signed=False)
        if flags & (1 << 4):
            writer.write_string(self.prompt)
        if flags & (1 << 2):
            writer.write_int(self.installs_count, signed=True)
        if flags & (1 << 3):
            writer.write_long(self.author_id, signed=False)
        if flags & (1 << 5):
            writer.write(bytes(self.example_english))
        return writer.get_bytes()
    @classmethod
    def from_reader(cls, reader):
        flags = reader.read_int(signed=False)
        creator = bool(flags & (1 << 0))
        id = reader.read_long()
        access_hash = reader.read_long()
        slug = reader.read_string()
        title = reader.read_string()
        if flags & (1 << 1):
            emoji_id = reader.read_long()
        else:
            emoji_id = None
        if flags & (1 << 4):
            prompt = reader.read_string()
        else:
            prompt = None
        if flags & (1 << 2):
            installs_count = reader.read_int()
        else:
            installs_count = None
        if flags & (1 << 3):
            author_id = reader.read_long()
        else:
            author_id = None
        if flags & (1 << 5):
            example_english = reader.tgread_object()
        else:
            example_english = None
        return cls(creator, id, access_hash, slug, title, emoji_id, prompt, installs_count, author_id, example_english)

